//   .S_AXIS_DATA_tdata(data_in),
//   .S_AXIS_DATA_tready(ready_signal128),
//   .S_AXIS_DATA_tvalid(data_in_valid),
//   .aclk(clock),
//   .aresetn(~reset)
//);

//mv_avg #(.DATA_WIDTH(16), .LOG2_AVG_LEN(7)) mv_avg_new_inst (
