reg reset;
reg [(IQ_DATA_WIDTH-1):0] data_in;
reg data_in_valid;
wire [(IQ_DATA_WIDTH-1):0] data_out;
wire data_out_valid;
reg [15:0] clk_count;

integer sample_count;

`define SPEED_100M // comment out this to use 200M

`define NUM_SAMPLE 1000

initial begin
    $dumpfile("fifo_sample_delay_tb.vcd");
    $dumpvars;

    data_in <= 0;
    data_in_valid <= 0;
    clk_count <= 0;
    sample_count = 0;
    clock = 0;

    reset = 1;
    #100 reset = 0;
    // 5clk reset (100MHz) at a specific time
    #1003 reset = 1;
    #57 reset = 0;
    // 5clk reset (100MHz) at a specific time
    #2005 reset = 1;
    #87 reset = 0;
    // 5clk reset (100MHz) at a specific time
    #3008 reset = 1;
    #50 reset = 0;
